mapper.select:
SELECT FROM employee WHERE deleted_at IS NULL
AND (employee_id ILIKE CONCAT('%', #{keyword}, '%') OR name ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY employee_id LIMIT #{limit} OFFSET #{offset}

mapper.sql:
FROM employee e LEFT JOIN affiliation a ON a.affiliation_id = e.affiliation_id AND a.deleted_at IS NULL WHERE e.deleted_at IS NULL
AND (e.employee_id ILIKE CONCAT('%', #{keyword}, '%') OR e.name ILIKE CONCAT('%', #{keyword}, '%'))
AND e.gender = #{gender}
AND e.employee_category = #{employeeCategory}
AND e.affiliation_id = #{affiliationId}
AND NOT EXISTS ( SELECT 1 FROM residence_history rh WHERE rh.employee_id = e.employee_id AND rh.deleted_at IS NULL AND rh.move_in_date <= CURRENT_DATE AND (rh.move_out_date IS NULL OR rh.move_out_date >= CURRENT_DATE) )
AND EXISTS ( SELECT 1 FROM residence_history rh_fee WHERE rh_fee.employee_id = e.employee_id AND rh_fee.deleted_at IS NULL AND rh_fee.move_in_date <= (to_date(#{targetYearMonth} || '-01', 'YYYY-MM-DD') + interval '1 month' - interval '1 day')::date AND (rh_fee.move_out_date IS NULL OR rh_fee.move_out_date >= to_date(#{targetYearMonth} || '-01', 'YYYY-MM-DD'))
AND rh_fee.dormitory_id = #{dormitoryId}
AND rh_fee.room_id = #{roomId}
)

mapper.select:
SELECT e.employee_id, e.name, e.gender, e.employee_category, e.affiliation_id, a.name AS affiliation_name, e.business_division, e.nearest_station_1, e.nearest_station_2, e.nearest_station_3, e.contact_info::text AS contact_info, e.updated_at, EXISTS ( SELECT 1 FROM residence_history rh WHERE rh.employee_id = e.employee_id AND rh.deleted_at IS NULL
AND rh.move_in_date <= (to_date(#{targetYearMonth} || '-01', 'YYYY-MM-DD') + interval '1 month' - interval '1 day')::date AND (rh.move_out_date IS NULL OR rh.move_out_date >= to_date(#{targetYearMonth} || '-01', 'YYYY-MM-DD'))
AND rh.dormitory_id = #{dormitoryId}
AND rh.room_id = #{roomId}
AND rh.move_in_date <= CURRENT_DATE AND (rh.move_out_date IS NULL OR rh.move_out_date >= CURRENT_DATE)
) AS residing
ORDER BY residing DESC, e.updated_at DESC, e.name ASC, e.employee_id ASC
ORDER BY e.updated_at DESC, e.employee_id
ORDER BY e.employee_id
LIMIT #{limit} OFFSET #{offset}
